import React, { Component } from 'react';
import './favs.css';

export default class Favs extends Component {

    render() {
        let c = [];

        items.sort((a,b)=>{return (a.tag>b.tag)?1:-1});

        for (let i = 0; i < items.length; i++) {
            c.push(
                <a href={items[i].link} className="Favs-Item" key={i}>
                    <div className="Favs-Tag">{items[i].tag.slice(0,3).toUpperCase()}</div>
                </a>
            );
        }

        return (
            <div className="Favs">
                <div style={{ width: "100px", height: "50px" }}></div>
                <div className="Favs-Content">
                    {c}
                </div>
            </div>
        );
    }
}

